13	// Handler exposes HTTP endpoints for the file vault module.
14	type Handler struct {
15		service *FileVaultService
16		logger  *zap.Logger
17	}
18	
19	// NewHandler creates a new file vault Handler.
20	func NewHandler(service *FileVaultService, logger *zap.Logger) *Handler {
21		return &Handler{service: service, logger: logger}
22	}
23	
24	// RegisterRoutes mounts file vault routes on the given Echo group.
25	// The group is expected to already have the "/files" prefix from the router.
26	func RegisterRoutes(g *echo.Group, h *Handler) {
27		g.POST("/upload", h.Upload)
28		g.POST("/:id/download-token", h.CreateDownloadToken)
29		g.GET("/download/:token", h.Download)
30		g.GET("/record/:recordType/:recordId", h.GetFilesForRecord)
31	}
32	
33	// Upload handles multipart file uploads.
34	func (h *Handler) Upload(c echo.Context) error {
35		userID := common.GetUserID(c)
36		if userID == "" {
37			return common.Error(c, http.StatusUnauthorized, "UNAUTHORIZED", "authentication required")
38		}
39	
40		file, header, err := c.Request().FormFile("file")
41		if err != nil {
42			return common.Error(c, http.StatusBadRequest, "BAD_REQUEST", "file is required")
43		}
44		defer file.Close()
45	
46		recordType := c.FormValue("recordType")
47		recordID := c.FormValue("recordId")
48		encrypt := c.FormValue("encrypt") == "true"
49	
50		meta, err := h.service.Upload(c.Request().Context(), userID, file, header, recordType, recordID, encrypt)
51		if err != nil {
52			return handleServiceError(c, err)
53		}
54	
55		return common.Created(c, meta)
56	}
57	
58	// createDownloadTokenRequest is the request body for creating a download token.
59	type createDownloadTokenRequest struct {
60		TTLSeconds int  `json:"ttlSeconds"`
61		SingleUse  bool `json:"singleUse"`
62	}
63	
64	// CreateDownloadToken generates a time-limited download token for a file.
65	func (h *Handler) CreateDownloadToken(c echo.Context) error {
66		userID := common.GetUserID(c)
67		if userID == "" {
68			return common.Error(c, http.StatusUnauthorized, "UNAUTHORIZED", "authentication required")
69		}
70	
71		fileID := c.Param("id")
72		if fileID == "" {
73			return common.Error(c, http.StatusBadRequest, "BAD_REQUEST", "file ID is required")
74		}
75	
76		var req createDownloadTokenRequest
77		if err := c.Bind(&req); err != nil {
78			return common.Error(c, http.StatusBadRequest, "BAD_REQUEST", "invalid request body")
79		}
80	
81		ttl := time.Duration(req.TTLSeconds) * time.Second
82	
83		dt, err := h.service.CreateDownloadToken(c.Request().Context(), fileID, userID, ttl, req.SingleUse)
84		if err != nil {
85			return handleServiceError(c, err)
86		}
87	
88		return common.Created(c, dt)
89	}
90	
91	// Download streams a file to the client using a valid download token.
92	func (h *Handler) Download(c echo.Context) error {
93		token := c.Param("token")
94		if token == "" {
95			return common.Error(c, http.StatusBadRequest, "BAD_REQUEST", "download token is required")
96		}
97	
98		reader, meta, err := h.service.Download(c.Request().Context(), token)
99		if err != nil {
100			return handleServiceError(c, err)
101		}
102		defer reader.Close()
103	
104		c.Response().Header().Set("Content-Disposition", "attachment; filename=\""+meta.OriginalFilename+"\"")
105		c.Response().Header().Set("Content-Type", meta.MimeType)
106	
107		return c.Stream(http.StatusOK, meta.MimeType, reader)
108	}
109	
110	// GetFilesForRecord returns all files linked to a given record.
111	func (h *Handler) GetFilesForRecord(c echo.Context) error {
112		userID := common.GetUserID(c)
113		if userID == "" {
114			return common.Error(c, http.StatusUnauthorized, "UNAUTHORIZED", "authentication required")
115		}
116	
117		recordType := c.Param("recordType")
118		recordID := c.Param("recordId")
119	
120		if recordType == "" || recordID == "" {
121			return common.Error(c, http.StatusBadRequest, "BAD_REQUEST", "recordType and recordId are required")
122		}
123	
124		roles := common.GetRoles(c)
125		files, err := h.service.GetFilesForRecord(c.Request().Context(), recordType, recordID, userID, roles)
126		if err != nil {
127			return handleServiceError(c, err)
128		}
129	
130		if files == nil {
131			files = []FileMetadata{}
132		}
133	
134		return common.Success(c, files)
135	}
136	
137	// handleServiceError maps domain errors to HTTP responses.
138	func handleServiceError(c echo.Context, err error) error {
139		if de, ok := err.(*common.DomainError); ok {
140			switch de.Code {
141			case common.ErrCodeNotFound:
142				return common.Error(c, http.StatusNotFound, de.Code, de.Message)
143			case common.ErrCodeForbidden:
144				return common.Error(c, http.StatusForbidden, de.Code, de.Message)
145			case common.ErrCodeConflict:
146				return common.Error(c, http.StatusConflict, de.Code, de.Message)
147			case common.ErrCodeBadRequest:
148				return common.Error(c, http.StatusBadRequest, de.Code, de.Message)
149			case common.ErrCodeValidation:
150				return common.Error(c, http.StatusUnprocessableEntity, de.Code, de.Message)
151			}
152		}
153		return common.Error(c, http.StatusInternalServerError, "INTERNAL_ERROR", "an unexpected error occurred")
154	}
