1	package files
2	
3	import (
4		"context"
5		"crypto/rand"
6		"crypto/sha256"
7		"encoding/hex"
8		"io"
9		"mime/multipart"
10		"os"
11		"path/filepath"
12		"time"
13	
14		"github.com/google/uuid"
15		"go.uber.org/zap"
16	
17		"travel-platform/apps/api/internal/common"
18		"travel-platform/apps/api/internal/config"
19	)
20	
21	// FileVaultService manages encrypted file storage and token-based downloads.
22	type FileVaultService struct {
23		repo   *Repository
24		cfg    *config.Config
25		logger *zap.Logger
26	}
27	
28	// NewFileVaultService creates a new FileVaultService.
29	func NewFileVaultService(repo *Repository, cfg *config.Config, logger *zap.Logger) *FileVaultService {
30		return &FileVaultService{repo: repo, cfg: cfg, logger: logger}
31	}
32	
33	// Upload stores a file on disk (optionally encrypted), saves metadata, and links to a record.
34	func (s *FileVaultService) Upload(
35		ctx context.Context,
36		userID string,
37		file multipart.File,
38		header *multipart.FileHeader,
39		recordType, recordID string,
40		encrypt bool,
41	) (*FileMetadata, error) {
42		// Read the entire file into memory for hashing and optional encryption.
43		data, err := io.ReadAll(file)
44		if err != nil {
45			return nil, common.NewInternalError("read uploaded file", err)
46		}
47	
48		// Compute SHA-256 hash.
49		hash := sha256.Sum256(data)
50		hashHex := hex.EncodeToString(hash[:])
51	
52		// Generate a unique storage key.
53		storageKey := uuid.New().String()
54	
55		var wrappedKey string
56		writeData := data
57	
58		if encrypt {
59			// Generate a random 256-bit data encryption key.
60			dek, err := GenerateDEK()
61			if err != nil {
62				return nil, common.NewInternalError("generate DEK", err)
63			}
64	
65			// Encrypt the file data with AES-256-GCM.
66			writeData, err = EncryptFile(data, dek)
67			if err != nil {
68				return nil, common.NewInternalError("encrypt file", err)
69			}
70	
71			// Wrap the DEK with the master key.
72			masterKey, err := hex.DecodeString(s.cfg.MasterEncryptionKey)
73			if err != nil {
74				return nil, common.NewInternalError("decode master key", err)
75			}
76			wrappedKey, err = WrapDEK(dek, masterKey)
77			if err != nil {
78				return nil, common.NewInternalError("wrap DEK", err)
79			}
80		}
81	
82		// Ensure vault directory exists.
83		vaultPath := s.cfg.FileVaultPath
84		if err := os.MkdirAll(vaultPath, 0o700); err != nil {
85			return nil, common.NewInternalError("create vault directory", err)
86		}
87	
88		// Write file to disk.
89		filePath := filepath.Join(vaultPath, storageKey)
90		if err := os.WriteFile(filePath, writeData, 0o600); err != nil {
91			return nil, common.NewInternalError("write file to disk", err)
92		}
93	
94		// Save metadata to database.
95		meta := &FileMetadata{
96			StorageKey:           storageKey,
97			OriginalFilename:     header.Filename,
98			MimeType:             header.Header.Get("Content-Type"),
99			ByteSize:             int64(len(data)),
100			SHA256:               hashHex,
101			Encrypted:            encrypt,
102			EncryptionKeyWrapped: wrappedKey,
103			OwnerUserID:          userID,
104			VisibilityScope:      "private",
105		}
106	
107		if err := s.repo.CreateFileMetadata(ctx, meta); err != nil {
108			// Clean up the written file on DB failure.
109			_ = os.Remove(filePath)
110			return nil, common.NewInternalError("save file metadata", err)
111		}
112	
113		// Link to record if provided.
114		if recordType != "" && recordID != "" {
115			if err := s.repo.CreateRecordLink(ctx, meta.ID, recordType, recordID); err != nil {
116				s.logger.Error("failed to link file to record",
117					zap.String("fileId", meta.ID),
118					zap.String("recordType", recordType),
119					zap.String("recordId", recordID),
120					zap.Error(err),
121				)
122			}
123		}
124	
125		s.logger.Info("file uploaded",
126			zap.String("fileId", meta.ID),
127			zap.String("storageKey", storageKey),
128			zap.Bool("encrypted", encrypt),
129		)
130	
131		return meta, nil
132	}
133	
134	// CreateDownloadToken generates a time-limited token for downloading a file.
135	func (s *FileVaultService) CreateDownloadToken(
136		ctx context.Context,
137		fileID, actorID string,
138		ttl time.Duration,
139		singleUse bool,
140	) (*DownloadToken, error) {
141		// Verify the file exists.
142		meta, err := s.repo.GetFileMetadataByID(ctx, fileID)
143		if err != nil {
144			return nil, err
145		}
146	
147		// Check permission: owner or admin role-based policy.
148		if meta.OwnerUserID != actorID {
149			hasPolicy, err := s.repo.HasAccessPolicy(ctx, fileID, common.RoleAdministrator)
150			if err != nil {
151				return nil, common.NewInternalError("check access policy", err)
152			}
153			if !hasPolicy {
154				return nil, common.NewForbiddenError("no permission to access this file")
155			}
156		}
157	
158		// Generate a crypto-random token.
159		tokenBytes := make([]byte, 32)
160		if _, err := io.ReadFull(rand.Reader, tokenBytes); err != nil {
161			return nil, common.NewInternalError("generate token", err)
162		}
163		tokenStr := hex.EncodeToString(tokenBytes)
164	
165		if ttl == 0 {
166			ttl = s.cfg.DownloadTokenTTL
167		}
168	
169		dt := &DownloadToken{
170			Token:     tokenStr,
171			FileID:    fileID,
172			ActorID:   actorID,
173			ExpiresAt: time.Now().UTC().Add(ttl),
174			SingleUse: singleUse,
175			Scope:     "download",
176		}
177	
178		if err := s.repo.CreateDownloadToken(ctx, dt); err != nil {
179			return nil, common.NewInternalError("save download token", err)
180		}
181	
182		s.logger.Info("download token created",
183			zap.String("fileId", fileID),
184			zap.String("actorId", actorID),
185			zap.Duration("ttl", ttl),
186		)
187	
188		return dt, nil
189	}
190	
191	// Download validates a token and returns a reader for the (decrypted) file contents.
192	func (s *FileVaultService) Download(ctx context.Context, token string) (io.ReadCloser, *FileMetadata, error) {
193		// Look up token.
194		dt, err := s.repo.GetDownloadTokenByToken(ctx, token)
195		if err != nil {
196			return nil, nil, err
197		}
198	
199		// Check expiration.
200		if time.Now().UTC().After(dt.ExpiresAt) {
201			return nil, nil, common.NewBadRequestError("download token has expired")
202		}
203	
204		// Check single-use consumption.
205		if dt.SingleUse && dt.ConsumedAt != nil {
206			return nil, nil, common.NewBadRequestError("download token has already been used")
207		}
208	
209		// Mark consumed if single-use.
210		if dt.SingleUse {
211			if err := s.repo.MarkTokenConsumed(ctx, dt.ID); err != nil {
212				return nil, nil, common.NewInternalError("mark token consumed", err)
213			}
214		}
215	
216		// Load file metadata.
217		meta, err := s.repo.GetFileMetadataByID(ctx, dt.FileID)
218		if err != nil {
219			return nil, nil, err
220		}
221	
222		// Read file from disk.
223		filePath := filepath.Join(s.cfg.FileVaultPath, meta.StorageKey)
224		data, err := os.ReadFile(filePath)
225		if err != nil {
226			return nil, nil, common.NewInternalError("read file from disk", err)
227		}
228	
229		// Decrypt if necessary.
230		if meta.Encrypted {
231			masterKey, err := hex.DecodeString(s.cfg.MasterEncryptionKey)
232			if err != nil {
233				return nil, nil, common.NewInternalError("decode master key", err)
234			}
235			dek, err := UnwrapDEK(meta.EncryptionKeyWrapped, masterKey)
236			if err != nil {
237				return nil, nil, common.NewInternalError("unwrap DEK", err)
238			}
239			data, err = DecryptFile(data, dek)
240			if err != nil {
241				return nil, nil, common.NewInternalError("decrypt file", err)
242			}
243		}
244	
245		reader := io.NopCloser(bytesReader(data))
246	
247		return reader, meta, nil
248	}
249	
250	// LinkToRecord associates a file with an external record.
251	func (s *FileVaultService) LinkToRecord(ctx context.Context, fileID, recordType, recordID string) error {
252		// Verify file exists.
253		if _, err := s.repo.GetFileMetadataByID(ctx, fileID); err != nil {
254			return err
255		}
256		return s.repo.CreateRecordLink(ctx, fileID, recordType, recordID)
257	}
258	
259	// GetFilesForRecord returns all files linked to a given record.
260	// Authorization: administrators and accountants can see all files; others can only see files they own.
261	func (s *FileVaultService) GetFilesForRecord(ctx context.Context, recordType, recordID, userID string, roles []string) ([]FileMetadata, error) {
262		files, err := s.repo.GetFilesForRecord(ctx, recordType, recordID)
263		if err != nil {
264			return nil, err
265		}
266	
267		// Admins and accountants can see all files for the record.
268		if common.IsAdminOrAccountant(roles) {
269			return files, nil
270		}
271	
272		// Others can only see files they own.
273		var filtered []FileMetadata
274		for _, f := range files {
275			if f.OwnerUserID == userID {
276				filtered = append(filtered, f)
277			}
278		}
279		return filtered, nil
280	}
281	
282	// bytesReader wraps a byte slice in an io.Reader.
283	type bytesReaderImpl struct {
284		data   []byte
285		offset int
286	}
287	
288	func bytesReader(data []byte) io.Reader {
289		return &bytesReaderImpl{data: data}
290	}
291	
292	func (r *bytesReaderImpl) Read(p []byte) (int, error) {
293		if r.offset >= len(r.data) {
294			return 0, io.EOF
295		}
296		n := copy(p, r.data[r.offset:])
297		r.offset += n
298		return n, nil
299	}
