9	)
10	
11	// RequireRole returns Echo middleware that checks whether the authenticated user
12	// has at least one of the specified roles.
13	func RequireRole(roles ...string) echo.MiddlewareFunc {
14		required := make(map[string]bool, len(roles))
15		for _, r := range roles {
16			required[r] = true
17		}
18	
19		return func(next echo.HandlerFunc) echo.HandlerFunc {
20			return func(c echo.Context) error {
21				userRoles := common.GetRoles(c)
22				if len(userRoles) == 0 {
23					return common.Error(c, http.StatusForbidden, "FORBIDDEN", "insufficient permissions")
24				}
25	
26				for _, r := range userRoles {
27					if required[r] {
28						return next(c)
29					}
30				}
31	
32				return common.Error(c, http.StatusForbidden, "FORBIDDEN", "insufficient permissions")
33			}
34		}
35	}
