1	package risk
2	
3	import (
4		"context"
5		"encoding/json"
6		"fmt"
7	
8		"go.uber.org/zap"
9	
10		"travel-platform/apps/api/internal/common"
11	)
12	
13	// Service handles risk business logic.
14	type Service struct {
15		repo   *Repository
16		engine *Engine
17		logger *zap.Logger
18	}
19	
20	// NewService creates a new risk service.
21	func NewService(repo *Repository, logger *zap.Logger) *Service {
22		return &Service{
23			repo:   repo,
24			engine: NewEngine(repo, logger),
25			logger: logger,
26		}
27	}
28	
29	// GetRiskSummary returns a comprehensive risk profile for a user.
30	func (s *Service) GetRiskSummary(ctx context.Context, userID string) (*RiskSummaryDTO, error) {
31		summary := &RiskSummaryDTO{UserID: userID}
32	
33		bl, err := s.repo.GetBlacklist(ctx, userID)
34		if err != nil {
35			return nil, common.NewInternalError("failed to check blacklist", err)
36		}
37		summary.IsBlacklisted = bl != nil
38	
39		rs, err := s.repo.GetRiskScore(ctx, userID)
40		if err != nil {
41			return nil, common.NewInternalError("failed to get risk score", err)
42		}
43		if rs != nil {
44			summary.Score = rs.Score
45		}
46	
47		throttles, err := s.repo.GetActiveThrottles(ctx, userID)
48		if err != nil {
49			return nil, common.NewInternalError("failed to get throttles", err)
50		}
51		summary.ActiveThrottles = make([]ThrottleActionDTO, 0, len(throttles))
52		for _, t := range throttles {
53			dto := ThrottleActionDTO{
54				ID:         t.ID,
55				ActionType: t.ActionType,
56				Reason:     t.Reason,
57				Active:     t.Active,
58				CreatedAt:  t.CreatedAt,
59			}
60			if t.ExpiresAt != nil {
61				dto.ExpiresAt = *t.ExpiresAt
62			}
63			summary.ActiveThrottles = append(summary.ActiveThrottles, dto)
64		}
65	
66		events, err := s.repo.GetRecentEvents(ctx, userID, 20)
67		if err != nil {
68			s.logger.Error("failed to get recent events", zap.Error(err))
69			events = nil
70		}
71		summary.RecentEvents = make([]RiskEventDTO, 0, len(events))
72		for _, e := range events {
73			summary.RecentEvents = append(summary.RecentEvents, RiskEventDTO{
74				ID:          e.ID,
75				EventType:   e.EventType,
76				Description: e.Description,
77				Severity:    e.Severity,
78				CreatedAt:   e.CreatedAt,
79			})
80		}
81	
82		return summary, nil
83	}
84	
85	// EvaluateAction checks risk for a user action.
86	func (s *Service) EvaluateAction(ctx context.Context, userID, actionType string) (*RiskDecision, error) {
87		return s.engine.EvaluateAction(ctx, userID, actionType)
88	}
89	
90	// RecordEvent records a risk event and evaluates.
91	func (s *Service) RecordEvent(ctx context.Context, userID, eventType, description, severity string) error {
92		metadata, _ := json.Marshal(map[string]string{"severity": severity})
93		return s.repo.CreateRiskEvent(ctx, RiskEvent{
94			UserID:       userID,
95			EventType:    eventType,
96			Description:  description,
97			Severity:     severity,
98			MetadataJSON: metadata,
99		})
100	}
101	
102	// BlacklistUser blacklists a user.
103	func (s *Service) BlacklistUser(ctx context.Context, targetID, adminID, reason string) error {
104		if reason == "" {
105			return common.NewBadRequestError("reason is required")
106		}
