16	// MaxDailyWithdrawal is the maximum amount a courier can withdraw per calendar day.
17	const MaxDailyWithdrawal = 2500.00
18	
19	// MinRefundAmount is the minimum refund adjustment unit.
20	const MinRefundAmount = 1.00
21	
22	// Service encapsulates business logic for the finance domain.
23	type Service struct {
24		repo    *Repository
25		riskSvc *risk.Service
26		logger  *zap.Logger
27	}
