38	// GetWallet returns a wallet for the given owner and type, with authorization check.
39	func (s *Service) GetWallet(ctx context.Context, ownerID string, walletType WalletType, requestingUserID string) (*WalletResponse, error) {
40		if ownerID != requestingUserID {
41			return nil, common.NewForbiddenError("you can only view your own wallet")
42		}
43	
44		w, err := s.repo.GetWallet(ctx, ownerID, walletType)
45		if err != nil {
46			return nil, err
47		}
48	
49		return &WalletResponse{
50			ID:         w.ID,
51			OwnerID:    w.OwnerID,
52			WalletType: w.WalletType,
53			Balance:    w.Balance,
54			Currency:   w.Currency,
55			CreatedAt:  w.CreatedAt,
56			UpdatedAt:  w.UpdatedAt,
57		}, nil
