60	// GetTransactions returns paginated transactions for a wallet.
61	func (s *Service) GetTransactions(ctx context.Context, walletID, userID string, page, pageSize int) (*PaginatedTransactions, error) {
62		// Verify wallet ownership.
63		w, err := s.repo.GetWalletByID(ctx, walletID)
64		if err != nil {
65			return nil, err
66		}
67		if w.OwnerID != nil && *w.OwnerID != userID {
68			return nil, common.NewForbiddenError("you can only view your own transactions")
69		}
70	
71		txns, total, err := s.repo.GetWalletTransactions(ctx, walletID, page, pageSize)
72		if err != nil {
73			return nil, common.NewInternalError("failed to fetch transactions", err)
74		}
75	
76		items := make([]TransactionResponse, 0, len(txns))
77		for _, t := range txns {
78			items = append(items, TransactionResponse{
79				ID:            t.ID,
80				WalletID:      t.WalletID,
81				Amount:        t.Amount,
82				Direction:     t.Direction,
83				ReferenceType: t.ReferenceType,
84				ReferenceID:   t.ReferenceID,
85				Description:   t.Description,
86				CreatedAt:     t.CreatedAt,
87			})
88		}
89	
90		totalPages := 0
91		if pageSize > 0 {
92			totalPages = (total + pageSize - 1) / pageSize
93		}
94	
95		return &PaginatedTransactions{
96			Items:      items,
97			Total:      total,
98			Page:       page,
99			PageSize:   pageSize,
100			TotalPages: totalPages,
101		}, nil
102	}
