104	// ---------------------------------------------------------------------------
105	// Tender
106	// ---------------------------------------------------------------------------
107	
108	// RecordTender creates a payment record and posts a journal entry.
109	func (s *Service) RecordTender(ctx context.Context, userID string, req RecordTenderRequest) error {
110		if req.Amount <= 0 {
111			return common.NewBadRequestError("amount must be positive")
112		}
113		if req.OrderID == "" || req.OrderType == "" {
114			return common.NewBadRequestError("orderType and orderId are required")
115		}
116	
117		p := &PaymentRecord{
118			OrderType:     req.OrderType,
119			OrderID:       req.OrderID,
120			TenderType:    req.TenderType,
121			Amount:        req.Amount,
122			Currency:      req.Currency,
123			ReferenceText: req.ReferenceText,
124			RecordedBy:    userID,
125		}
126	
127		paymentID, err := s.repo.CreatePaymentRecord(ctx, p)
128		if err != nil {
129			return common.NewInternalError("failed to record payment", err)
130		}
131	
132		// Post journal entry: debit ManualTenderClearing, credit CashOnHand.
133		tx, err := s.repo.BeginTx(ctx)
134		if err != nil {
135			return common.NewInternalError("failed to begin transaction", err)
136		}
137		defer func() { _ = tx.Rollback(ctx) }()
138	
139		refID, _ := uuid.Parse(paymentID)
140		err = PostJournalEntry(ctx, tx, "tender_recording", "payment_record", refID, fmt.Sprintf("Tender recorded for %s %s", req.OrderType, req.OrderID), userID, []JournalLine{
141			{AccountCode: ManualTenderClearing, Direction: Debit, Amount: req.Amount},
142			{AccountCode: CashOnHand, Direction: Credit, Amount: req.Amount},
143		})
144		if err != nil {
145			return common.NewInternalError("failed to post journal entry", err)
146		}
147	
148		return tx.Commit(ctx)
149	}
150	
151	// ---------------------------------------------------------------------------
152	// Refunds
153	// ---------------------------------------------------------------------------
154	
155	// ProcessRefund validates and creates a refund with journal entries.
156	func (s *Service) ProcessRefund(ctx context.Context, userID string, req RefundRequest) error {
157		// Risk gate: evaluate before processing refund.
158		if s.riskSvc != nil {
159			decision, err := s.riskSvc.EvaluateAction(ctx, userID, common.RiskActionProcessRefund)
160			if err == nil && !decision.Allowed {
161				return common.NewForbiddenError("action blocked by risk engine: " + decision.Reason)
162			}
163		}
164	
165		// Validate minimum refund amount.
166		if req.Amount < MinRefundAmount {
167			return common.NewBadRequestError(fmt.Sprintf("refund amount must be at least $%.2f", MinRefundAmount))
168		}
169	
170		// Validate whole dollars.
171		if math.Mod(req.Amount*100, 100) != 0 {
172			return common.NewBadRequestError("refund amount must be in whole dollars (multiples of 1.00)")
173		}
174	
175		if req.OrderID == "" || req.OrderType == "" {
176			return common.NewBadRequestError("orderType and orderId are required")
177		}
178	
179		// Create refund record.
180		refund := &Refund{
181			OrderType:    req.OrderType,
182			OrderID:      req.OrderID,
183			RefundAmount: req.Amount,
184			RefundReason: req.Reason,
185			CreatedBy:    userID,
186			Status:       RefundStatusApproved,
187		}
188	
189		refundID, err := s.repo.CreateRefund(ctx, refund)
190		if err != nil {
191			return common.NewInternalError("failed to create refund", err)
192		}
193	
194		// Create refund items.
195		for _, item := range req.Items {
196			ri := &RefundItem{
197				RefundID: refundID,
198				ItemID:   item.ItemID,
199				ItemType: item.ItemType,
200				Amount:   item.Amount,
201			}
202			if err := s.repo.CreateRefundItem(ctx, ri); err != nil {
203				s.logger.Error("failed to create refund item", zap.Error(err))
204			}
205		}
206	
207		// Post journal entries.
208		tx, err := s.repo.BeginTx(ctx)
209		if err != nil {
210			return common.NewInternalError("failed to begin transaction", err)
211		}
212		defer func() { _ = tx.Rollback(ctx) }()
213	
214		refUUID, _ := uuid.Parse(refundID)
215		err = PostJournalEntry(ctx, tx, "refund", "refund", refUUID, fmt.Sprintf("Refund for %s %s: %s", req.OrderType, req.OrderID, req.Reason), userID, []JournalLine{
216			{AccountCode: EscrowLiability, Direction: Debit, Amount: req.Amount},
217			{AccountCode: CashOnHand, Direction: Credit, Amount: req.Amount},
218		})
219		if err != nil {
220			return common.NewInternalError("failed to post refund journal entry", err)
221		}
222	
223		// Update escrow refunded amount.
224		escrow, err := s.repo.GetEscrow(ctx, req.OrderType, req.OrderID)
225		if err == nil {
226			if err := s.repo.UpdateEscrowRefunded(ctx, tx, escrow.ID, req.Amount); err != nil {
227				s.logger.Error("failed to update escrow refunded", zap.Error(err))
228			}
229		}
230	
231		return tx.Commit(ctx)
232	}
233	
234	// ---------------------------------------------------------------------------
235	// Withdrawals
236	// ---------------------------------------------------------------------------
237	
238	// RequestWithdrawal creates a withdrawal request, checking the daily cap.
239	func (s *Service) RequestWithdrawal(ctx context.Context, courierID string, req WithdrawalCreateRequest) (*WithdrawalRequestDTO, error) {
240		// Risk gate: evaluate before withdrawal.
241		if s.riskSvc != nil {
242			decision, err := s.riskSvc.EvaluateAction(ctx, courierID, common.RiskActionRequestWithdrawal)
243			if err == nil && !decision.Allowed {
244				return nil, common.NewForbiddenError("action blocked by risk engine: " + decision.Reason)
245			}
246		}
247	
248		if req.Amount <= 0 {
249			return nil, common.NewBadRequestError("withdrawal amount must be positive")
250		}
251	
252		// Check daily cap.
253		now := time.Now()
254		dailyTotal, err := s.repo.GetDailyWithdrawalTotal(ctx, courierID, now)
255		if err != nil {
256			return nil, common.NewInternalError("failed to check daily withdrawal total", err)
257		}
258	
259		if dailyTotal+req.Amount > MaxDailyWithdrawal {
260			remaining := MaxDailyWithdrawal - dailyTotal
261			return nil, common.NewBadRequestError(fmt.Sprintf("daily withdrawal cap exceeded; remaining allowance: $%.2f", remaining))
262		}
263	
264		wr := &WithdrawalRequest{
265			CourierID:     courierID,
266			RequestAmount: req.Amount,
267			Status:        WithdrawalStatusRequested,
268		}
269	
270		id, err := s.repo.CreateWithdrawalRequest(ctx, wr)
271		if err != nil {
272			return nil, common.NewInternalError("failed to create withdrawal request", err)
273		}
274	
275		created, err := s.repo.GetWithdrawalRequest(ctx, id)
276		if err != nil {
277			return nil, common.NewInternalError("failed to fetch withdrawal request", err)
278		}
279	
280		return &WithdrawalRequestDTO{
281			ID:            created.ID,
282			CourierID:     created.CourierID,
283			RequestAmount: created.RequestAmount,
284			Status:        created.Status,
285			RequestedAt:   created.RequestedAt,
286			CreatedAt:     created.CreatedAt,
287		}, nil
288	}
289	
290	// ApproveWithdrawal approves a withdrawal, rechecks the daily cap, posts journal entries, and creates a disbursement.
291	func (s *Service) ApproveWithdrawal(ctx context.Context, withdrawalID, approverID string) error {
292		wr, err := s.repo.GetWithdrawalRequest(ctx, withdrawalID)
293		if err != nil {
294			return err
295		}
296	
297		if wr.Status != WithdrawalStatusRequested {
298			return common.NewConflictError("withdrawal request is not in a requestable state")
299		}
300	
301		// Recheck daily cap at approval time.
302		now := time.Now()
303		dailyTotal, err := s.repo.GetDailyWithdrawalTotal(ctx, wr.CourierID, now)
304		if err != nil {
305			return common.NewInternalError("failed to check daily withdrawal total", err)
306		}
307		if dailyTotal > MaxDailyWithdrawal {
308			return common.NewBadRequestError("daily withdrawal cap would be exceeded at approval time")
309		}
310	
311		// Post journal entries.
312		tx, err := s.repo.BeginTx(ctx)
313		if err != nil {
314			return common.NewInternalError("failed to begin transaction", err)
315		}
316		defer func() { _ = tx.Rollback(ctx) }()
317	
318		refUUID, _ := uuid.Parse(withdrawalID)
319		err = PostJournalEntry(ctx, tx, "withdrawal_disbursement", "withdrawal_request", refUUID, fmt.Sprintf("Withdrawal disbursement for courier %s", wr.CourierID), approverID, []JournalLine{
320			{AccountCode: CourierPayable, Direction: Debit, Amount: wr.RequestAmount},
321			{AccountCode: CashOnHand, Direction: Credit, Amount: wr.RequestAmount},
322		})
323		if err != nil {
324			return common.NewInternalError("failed to post withdrawal journal entry", err)
325		}
326	
327		if err := tx.Commit(ctx); err != nil {
328			return common.NewInternalError("failed to commit transaction", err)
329		}
330	
331		// Create disbursement record.
332		if err := s.repo.CreateWithdrawalDisbursement(ctx, withdrawalID, wr.RequestAmount); err != nil {
333			s.logger.Error("failed to create disbursement record", zap.Error(err))
334		}
335	
336		// Update status to settled.
337		if err := s.repo.UpdateWithdrawalApproval(ctx, withdrawalID, approverID, string(WithdrawalStatusSettled)); err != nil {
338			return common.NewInternalError("failed to update withdrawal status", err)
339		}
340	
341		return nil
342	}
343	
344	// RejectWithdrawal rejects a withdrawal request.
345	func (s *Service) RejectWithdrawal(ctx context.Context, withdrawalID, approverID, reason string) error {
346		wr, err := s.repo.GetWithdrawalRequest(ctx, withdrawalID)
347		if err != nil {
348			return err
349		}
350	
351		if wr.Status != WithdrawalStatusRequested {
352			return common.NewConflictError("withdrawal request is not in a requestable state")
353		}
354	
355		if reason == "" {
356			return common.NewBadRequestError("rejection reason is required")
357		}
358	
359		return s.repo.UpdateWithdrawalRejection(ctx, withdrawalID, approverID, reason)
360	}
361	
362	// GetActiveEscrows returns active escrow accounts related to the given owner.
363	func (s *Service) GetActiveEscrows(ctx context.Context, ownerID string) ([]EscrowSummary, error) {
364		return s.repo.GetActiveEscrowsByOwner(ctx, ownerID)
365	}
366	
367	// ---------------------------------------------------------------------------
368	// Escrow Release
369	// ---------------------------------------------------------------------------
370	
371	// ReleaseEscrow releases funds from escrow with journal entries.
372	func (s *Service) ReleaseEscrow(ctx context.Context, orderType, orderID string, amount float64, createdBy string) error {
373		if amount <= 0 {
374			return common.NewBadRequestError("release amount must be positive")
375		}
376	
377		escrow, err := s.repo.GetEscrow(ctx, orderType, orderID)
378		if err != nil {
379			return err
380		}
381	
382		remaining := escrow.AmountHeld - escrow.AmountReleased - escrow.AmountRefunded
383		if amount > remaining {
384			return common.NewBadRequestError(fmt.Sprintf("release amount exceeds remaining escrow balance of $%.2f", remaining))
385		}
386	
387		tx, err := s.repo.BeginTx(ctx)
388		if err != nil {
389			return common.NewInternalError("failed to begin transaction", err)
390		}
391		defer func() { _ = tx.Rollback(ctx) }()
392	
393		// Update escrow.
394		if err := s.repo.UpdateEscrowReleased(ctx, tx, escrow.ID, amount); err != nil {
395			return common.NewInternalError("failed to update escrow", err)
396		}
397	
398		// Post journal entries.
399		refUUID, _ := uuid.Parse(orderID)
400		err = PostJournalEntry(ctx, tx, "escrow_release", orderType, refUUID, fmt.Sprintf("Escrow release for %s %s", orderType, orderID), createdBy, []JournalLine{
401			{AccountCode: EscrowLiability, Direction: Debit, Amount: amount},
402			{AccountCode: SupplierPayable, Direction: Credit, Amount: amount},
403		})
404		if err != nil {
405			return common.NewInternalError("failed to post escrow release journal entry", err)
406		}
407	
408		return tx.Commit(ctx)
409	}
