415	// GetReconciliation returns a computed reconciliation report.
416	func (s *Service) GetReconciliation(ctx context.Context) (*ReconciliationReportDTO, error) {
417		report, err := s.repo.GetReconciliationSummary(ctx)
418		if err != nil {
419			return nil, common.NewInternalError("failed to generate reconciliation report", err)
420		}
421		return report, nil
422	}
