12	
13	// Handler exposes HTTP endpoints for the contracts and invoices module.
14	type Handler struct {
15		service *ContractService
16		logger  *zap.Logger
17	}
18	
19	// NewHandler creates a new contracts Handler.
20	func NewHandler(service *ContractService, logger *zap.Logger) *Handler {
21		return &Handler{service: service, logger: logger}
22	}
23	
24	// RegisterRoutes mounts contract and invoice routes on the given Echo group.
25	func RegisterRoutes(g *echo.Group, h *Handler) {
26		g.GET("/contract-templates", h.ListTemplates)
27		g.POST("/contracts/generate", h.GenerateContract)
28		g.POST("/invoice-requests", h.RequestInvoice)
29		g.POST("/invoice-requests/:id/approve", h.ApproveInvoiceRequest, middleware.RequireRole(common.RoleAdministrator, common.RoleAccountant))
30		g.POST("/invoices/:id/generate", h.GenerateInvoice, middleware.RequireRole(common.RoleAdministrator, common.RoleAccountant))
31		g.GET("/invoice-requests", h.ListInvoiceRequests)
32	}
33	
34	// ListTemplates returns all active contract templates.
35	func (h *Handler) ListTemplates(c echo.Context) error {
36		templates, err := h.service.GetTemplates(c.Request().Context())
37		if err != nil {
38			return handleServiceError(c, err)
39		}
40	
41		if templates == nil {
42			templates = []ContractTemplate{}
43		}
44	
45		return common.Success(c, templates)
46	}
47	
48	// GenerateContract renders a contract from a template.
49	func (h *Handler) GenerateContract(c echo.Context) error {
50		userID := common.GetUserID(c)
51		if userID == "" {
52			return common.Error(c, http.StatusUnauthorized, "UNAUTHORIZED", "authentication required")
53		}
54	
55		var req GenerateContractRequest
56		if err := c.Bind(&req); err != nil {
57			return common.Error(c, http.StatusBadRequest, "BAD_REQUEST", "invalid request body")
58		}
59	
60		result, err := h.service.GenerateContract(c.Request().Context(), userID, req)
61		if err != nil {
62			return handleServiceError(c, err)
63		}
64	
65		return common.Created(c, result)
66	}
67	
68	// RequestInvoice creates a new invoice request.
69	func (h *Handler) RequestInvoice(c echo.Context) error {
70		userID := common.GetUserID(c)
71		if userID == "" {
72			return common.Error(c, http.StatusUnauthorized, "UNAUTHORIZED", "authentication required")
73		}
74	
75		var req CreateInvoiceRequestDTO
76		if err := c.Bind(&req); err != nil {
77			return common.Error(c, http.StatusBadRequest, "BAD_REQUEST", "invalid request body")
78		}
79	
80		ir, err := h.service.RequestInvoice(c.Request().Context(), userID, req)
81		if err != nil {
