156	// handleServiceError maps domain errors to HTTP responses.
157	func handleServiceError(c echo.Context, err error) error {
158		if de, ok := err.(*common.DomainError); ok {
159			switch de.Code {
160			case common.ErrCodeNotFound:
161				return common.Error(c, http.StatusNotFound, de.Code, de.Message)
162			case common.ErrCodeForbidden:
163				return common.Error(c, http.StatusForbidden, de.Code, de.Message)
164			case common.ErrCodeConflict:
165				return common.Error(c, http.StatusConflict, de.Code, de.Message)
166			case common.ErrCodeBadRequest:
167				return common.Error(c, http.StatusBadRequest, de.Code, de.Message)
168			case common.ErrCodeValidation:
169				return common.Error(c, http.StatusUnprocessableEntity, de.Code, de.Message)
170			}
171		}
172		return common.Error(c, http.StatusInternalServerError, "INTERNAL_ERROR", "an unexpected error occurred")
173	}
