1	package risk
2	
3	import (
4		"context"
5		"encoding/json"
6		"time"
7	
8		"go.uber.org/zap"
9	)
10	
11	// Engine evaluates risk for user actions.
12	type Engine struct {
13		repo   *Repository
14		logger *zap.Logger
15	}
16	
17	// NewEngine creates a new risk engine.
18	func NewEngine(repo *Repository, logger *zap.Logger) *Engine {
19		return &Engine{repo: repo, logger: logger}
20	}
21	
22	// EvaluateAction checks if a user can perform an action based on risk rules.
23	func (e *Engine) EvaluateAction(ctx context.Context, userID, actionType string) (*RiskDecision, error) {
24		// 1. Check blacklist first.
25		bl, err := e.repo.GetBlacklist(ctx, userID)
26		if err != nil {
27			return nil, err
28		}
29		if bl != nil {
30			return &RiskDecision{Allowed: false, Reason: "account is blacklisted: " + bl.Reason}, nil
31		}
32	
33		// 2. Check active throttles.
34		throttled, _, err := e.repo.IsThrottled(ctx, userID, actionType)
35		if err != nil {
36			return nil, err
37		}
38		if throttled {
39			return &RiskDecision{Allowed: false, Reason: "action is currently throttled"}, nil
40		}
41	
42		// 3. Heuristic: >8 cancellations in 24 hours -> auto-throttle, require admin approval.
43		cancellations, err := e.repo.CountCancellationsInWindow(ctx, userID, 24)
44		if err != nil {
45			e.logger.Error("failed to count cancellations", zap.Error(err))
46		} else if cancellations > 8 {
47			expires := time.Now().Add(6 * time.Hour)
48			_ = e.repo.CreateThrottle(ctx, ThrottleAction{
49				UserID:     userID,
50				ActionType: actionType,
51				Reason:     "exceeded 8 cancellations in 24 hours",
52				ExpiresAt:  &expires,
53			})
54			_ = e.repo.CreateAdminApproval(ctx, AdminApproval{
55				UserID:        &userID,
56				ActionType:    actionType,
57				ReferenceType: "cancellation_throttle",
58				ReferenceID:   userID,
59				RequestedBy:   "system",
60			})
61			return &RiskDecision{Allowed: false, RequireApproval: true, Reason: "too many cancellations in 24 hours"}, nil
62		}
63	
64		// 4. Heuristic: 20 RFQs in 10 minutes -> auto-throttle.
65		if actionType == "create_rfq" {
66			rfqCount, err := e.repo.CountRFQsInWindow(ctx, userID, 10)
67			if err != nil {
68				e.logger.Error("failed to count RFQs", zap.Error(err))
69			} else if rfqCount >= 20 {
70				expires := time.Now().Add(1 * time.Hour)
71				_ = e.repo.CreateThrottle(ctx, ThrottleAction{
72					UserID:     userID,
73					ActionType: "create_rfq",
74					Reason:     "exceeded 20 RFQs in 10 minutes",
75					ExpiresAt:  &expires,
76				})
77				return &RiskDecision{Allowed: false, Reason: "too many RFQ requests"}, nil
78			}
79		}
80	
81		// 5. Heuristic: repeated harassment flags (>=3) -> temporary freeze.
82		flags, err := e.repo.CountHarassmentFlags(ctx, userID)
83		if err != nil {
84			e.logger.Error("failed to count harassment flags", zap.Error(err))
85		} else if flags >= 3 {
86			expires := time.Now().Add(24 * time.Hour)
87			_ = e.repo.CreateThrottle(ctx, ThrottleAction{
88				UserID:     userID,
89				ActionType: "*",
90				Reason:     "multiple harassment flags",
91				ExpiresAt:  &expires,
92			})
93			return &RiskDecision{Allowed: false, Reason: "account frozen due to multiple harassment reports"}, nil
94		}
95	
96		return &RiskDecision{Allowed: true}, nil
97	}
98	
99	// RecordAndEvaluate records a risk event, recomputes score, and evaluates thresholds.
100	func (e *Engine) RecordAndEvaluate(ctx context.Context, userID, eventType, description string, metadata map[string]interface{}) (*RiskDecision, error) {
101		metadataJSON, _ := json.Marshal(metadata)
102	
103		err := e.repo.CreateRiskEvent(ctx, RiskEvent{
104			UserID:       userID,
105			EventType:    eventType,
106			Description:  description,
107			Severity:     determineSeverity(eventType),
108			MetadataJSON: metadataJSON,
109		})
110		if err != nil {
111			return nil, err
112		}
113	
114		_, err = e.repo.ComputeAndSaveRiskScore(ctx, userID)
115		if err != nil {
116			e.logger.Error("failed to compute risk score", zap.Error(err))
117		}
118	
119		return e.EvaluateAction(ctx, userID, eventType)
120	}
121	
122	// determineSeverity maps event types to severity levels.
123	func determineSeverity(eventType string) string {
124		switch eventType {
125		case "harassment_flag":
126			return "high"
127		case "cancellation":
128			return "medium"
129		case "rfq_creation":
130			return "low"
131		default:
132			return "low"
133		}
134	}
