1	package auth
2	
3	import (
4		"context"
5		"errors"
6		"fmt"
7		"time"
8	
9		"github.com/golang-jwt/jwt/v5"
10		"github.com/jackc/pgx/v5"
11		"github.com/jackc/pgx/v5/pgxpool"
12		"go.uber.org/zap"
13		"golang.org/x/crypto/bcrypt"
14	)
15	
16	// Claims represents the JWT claims for an authenticated user.
17	type Claims struct {
18		UserID string   `json:"user_id"`
19		Email  string   `json:"email"`
20		Roles  []string `json:"roles"`
21		jwt.RegisteredClaims
22	}
23	
24	// Service handles authentication operations.
25	type Service struct {
26		db        *pgxpool.Pool
27		logger    *zap.Logger
28		jwtSecret []byte
29		tokenTTL  time.Duration
30	}
31	
32	// NewService creates a new auth service.
33	func NewService(db *pgxpool.Pool, logger *zap.Logger, jwtSecret string) *Service {
34		return &Service{
35			db:        db,
36			logger:    logger,
37			jwtSecret: []byte(jwtSecret),
38			tokenTTL:  24 * time.Hour,
39		}
40	}
41	
42	// Login authenticates a user by email and password, returning a JWT token.
43	func (s *Service) Login(ctx context.Context, email, password string) (string, error) {
44		var (
45			userID       string
46			passwordHash string
47			status       string
48		)
49	
50		err := s.db.QueryRow(ctx,
51			`SELECT id, password_hash, status FROM users WHERE email = $1 AND deleted_at IS NULL`,
52			email,
53		).Scan(&userID, &passwordHash, &status)
54	
55		if err != nil {
56			if errors.Is(err, pgx.ErrNoRows) {
57				return "", fmt.Errorf("invalid credentials")
58			}
59			return "", fmt.Errorf("query user: %w", err)
60		}
61	
62		if status != "active" {
63			return "", fmt.Errorf("account is %s", status)
64		}
65	
66		if err := CheckPassword(passwordHash, password); err != nil {
67			return "", fmt.Errorf("invalid credentials")
68		}
69	
70		// Fetch user roles from join table.
71		roles, err := s.getUserRoles(ctx, userID)
72		if err != nil {
73			return "", fmt.Errorf("get roles: %w", err)
74		}
75	
76		token, err := s.generateToken(userID, email, roles)
77		if err != nil {
78			return "", fmt.Errorf("generate token: %w", err)
79		}
80	
81		return token, nil
82	}
83	
84	// getUserRoles fetches role names for a user from the user_roles join table.
85	func (s *Service) getUserRoles(ctx context.Context, userID string) ([]string, error) {
86		rows, err := s.db.Query(ctx,
87			`SELECT r.name FROM roles r
88			 JOIN user_roles ur ON ur.role_id = r.id
89			 WHERE ur.user_id = $1`,
90			userID,
91		)
92		if err != nil {
93			return nil, err
94		}
95		defer rows.Close()
96	
97		var roles []string
98		for rows.Next() {
99			var role string
100			if err := rows.Scan(&role); err != nil {
101				return nil, err
102			}
103			roles = append(roles, role)
104		}
105		return roles, rows.Err()
106	}
107	
108	// ValidateToken parses and validates a JWT token, returning the claims.
109	func (s *Service) ValidateToken(tokenStr string) (*Claims, error) {
110		claims := &Claims{}
111	
112		token, err := jwt.ParseWithClaims(tokenStr, claims, func(t *jwt.Token) (interface{}, error) {
113			if _, ok := t.Method.(*jwt.SigningMethodHMAC); !ok {
114				return nil, fmt.Errorf("unexpected signing method: %v", t.Header["alg"])
115			}
116			return s.jwtSecret, nil
117		})
118		if err != nil {
119			return nil, fmt.Errorf("parse token: %w", err)
120		}
121	
122		if !token.Valid {
123			return nil, fmt.Errorf("invalid token")
124		}
125	
126		return claims, nil
127	}
128	
129	// HashPassword hashes a plaintext password using bcrypt.
130	func HashPassword(password string) (string, error) {
131		bytes, err := bcrypt.GenerateFromPassword([]byte(password), bcrypt.DefaultCost)
132		if err != nil {
133			return "", fmt.Errorf("hash password: %w", err)
134		}
135		return string(bytes), nil
136	}
137	
138	// CheckPassword compares a bcrypt hash with a plaintext password.
139	func CheckPassword(hash, password string) error {
140		return bcrypt.CompareHashAndPassword([]byte(hash), []byte(password))
141	}
142	
143	// GetUserByID retrieves basic user info for the /me endpoint.
144	func (s *Service) GetUserByID(ctx context.Context, userID string) (map[string]interface{}, error) {
145		var (
146			id          string
147			email       string
148			status      string
149			displayName *string
150		)
151	
152		err := s.db.QueryRow(ctx,
153			`SELECT u.id, u.email, u.status, p.display_name
154			 FROM users u
155			 LEFT JOIN user_profiles p ON p.user_id = u.id
156			 WHERE u.id = $1 AND u.deleted_at IS NULL`,
157			userID,
158		).Scan(&id, &email, &status, &displayName)
159	
160		if err != nil {
161			if errors.Is(err, pgx.ErrNoRows) {
162				return nil, fmt.Errorf("user not found")
163			}
164			return nil, fmt.Errorf("query user: %w", err)
165		}
166	
167		roles, err := s.getUserRoles(ctx, userID)
168		if err != nil {
169			return nil, fmt.Errorf("get roles: %w", err)
170		}
171	
172		name := ""
173		if displayName != nil {
174			name = *displayName
175		}
176	
177		return map[string]interface{}{
178			"id":     id,
179			"email":  email,
180			"name":   name,
181			"status": status,
182			"roles":  roles,
183		}, nil
184	}
185	
186	// GenerateTestToken is a test-only helper that creates a signed JWT.
187	// It should only be used in test code.
188	func (s *Service) GenerateTestToken(userID, email string, roles []string) (string, error) {
189		return s.generateToken(userID, email, roles)
190	}
191	
192	func (s *Service) generateToken(userID, email string, roles []string) (string, error) {
193		now := time.Now()
194		claims := &Claims{
195			UserID: userID,
196			Email:  email,
197			Roles:  roles,
198			RegisteredClaims: jwt.RegisteredClaims{
199				ExpiresAt: jwt.NewNumericDate(now.Add(s.tokenTTL)),
200				IssuedAt:  jwt.NewNumericDate(now),
201				NotBefore: jwt.NewNumericDate(now),
202				Issuer:    "travel-platform",
203				Subject:   userID,
204			},
205		}
206	
207		token := jwt.NewWithClaims(jwt.SigningMethodHS256, claims)
208		return token.SignedString(s.jwtSecret)
209	}
