1	package db
2	
3	import (
4		"context"
5		"fmt"
6		"os"
7		"path/filepath"
8		"sort"
9		"strings"
10	
11		"github.com/jackc/pgx/v5/pgxpool"
12		"go.uber.org/zap"
13	)
14	
15	// migrationsDir returns the directory containing SQL migration files.
16	// Configurable via MIGRATIONS_DIR env var; defaults to infra/sql/migrations.
17	func migrationsDir() string {
18		if dir := os.Getenv("MIGRATIONS_DIR"); dir != "" {
19			return dir
20		}
21		return "infra/sql/migrations"
22	}
23	
24	// RunMigrations reads .sql files from the migrations directory and executes
25	// them in lexicographic order. It tracks applied migrations in a
26	// schema_migrations table to avoid re-running them.
27	func RunMigrations(ctx context.Context, pool *pgxpool.Pool, logger *zap.Logger) error {
28		// Ensure the tracking table exists.
29		if _, err := pool.Exec(ctx, `
30			CREATE TABLE IF NOT EXISTS schema_migrations (
31				version TEXT PRIMARY KEY,
32				applied_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
33			)
34		`); err != nil {
35			return fmt.Errorf("create schema_migrations table: %w", err)
36		}
37	
38		// Read migration files.
39		entries, err := os.ReadDir(migrationsDir())
40		if err != nil {
41			if os.IsNotExist(err) {
42				logger.Info("no migrations directory found, skipping migrations", zap.String("dir", migrationsDir()))
43				return nil
44			}
45			return fmt.Errorf("read migrations dir: %w", err)
46		}
47	
48		// Collect and sort .sql files.
49		var files []string
50		for _, e := range entries {
51			if !e.IsDir() && strings.HasSuffix(e.Name(), ".sql") {
52				files = append(files, e.Name())
53			}
54		}
55		sort.Strings(files)
56	
57		for _, name := range files {
58			// Check if already applied.
59			var exists bool
60			err := pool.QueryRow(ctx, "SELECT EXISTS(SELECT 1 FROM schema_migrations WHERE version = $1)", name).Scan(&exists)
61			if err != nil {
62				return fmt.Errorf("check migration %s: %w", name, err)
63			}
64			if exists {
65				continue
66			}
67	
68			// Read and execute.
69			content, err := os.ReadFile(filepath.Join(migrationsDir(), name))
70			if err != nil {
71				return fmt.Errorf("read migration %s: %w", name, err)
72			}
73	
74			logger.Info("applying migration", zap.String("version", name))
75	
76			tx, err := pool.Begin(ctx)
77			if err != nil {
78				return fmt.Errorf("begin tx for migration %s: %w", name, err)
79			}
80	
81			if _, err := tx.Exec(ctx, string(content)); err != nil {
82				_ = tx.Rollback(ctx)
83				return fmt.Errorf("execute migration %s: %w", name, err)
84			}
85	
86			if _, err := tx.Exec(ctx, "INSERT INTO schema_migrations (version) VALUES ($1)", name); err != nil {
87				_ = tx.Rollback(ctx)
88				return fmt.Errorf("record migration %s: %w", name, err)
89			}
90	
91			if err := tx.Commit(ctx); err != nil {
92				return fmt.Errorf("commit migration %s: %w", name, err)
93			}
94	
95			logger.Info("migration applied", zap.String("version", name))
96		}
97	
98		return nil
99	}
