14	// Handler exposes risk HTTP endpoints.
15	type Handler struct {
16		svc    *Service
17		logger *zap.Logger
18	}
19	
20	// NewHandler creates a new risk handler.
21	func NewHandler(svc *Service, logger *zap.Logger) *Handler {
22		return &Handler{svc: svc, logger: logger}
23	}
24	
25	// RegisterRoutes mounts risk routes.
26	func (h *Handler) RegisterRoutes(g *echo.Group, adminGroup *echo.Group) {
27		adminOnly := middleware.RequireRole(common.RoleAdministrator)
28	
29		g.GET("/risk/:userId", h.GetRiskSummary, adminOnly)
30	
31		admin := adminGroup.Group("", adminOnly)
32		admin.GET("/approvals", h.GetPendingApprovals)
33		admin.POST("/approvals/:id/resolve", h.ResolveApproval)
34		admin.POST("/users/:id/blacklist", h.BlacklistUser)
35		admin.POST("/users/:id/unblacklist", h.UnblacklistUser)
36	}
37	
38	// GetRiskSummary handles GET /api/v1/risk/:userId.
39	func (h *Handler) GetRiskSummary(c echo.Context) error {
40		userID := c.Param("userId")
41	
42		summary, err := h.svc.GetRiskSummary(c.Request().Context(), userID)
