{"file_path": "/c/Users/yonim/w2t80/repo/apps/api/internal/integration_test.go", "content": "package internal

import (
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"strings"
	"testing"

	"travel-platform/apps/api/internal/auth"
	"travel-platform/apps/api/internal/common"
	"travel-platform/apps/api/internal/middleware"

	"github.com/labstack/echo/v4"
)

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

const testJWTSecret = "integration-test-secret-key-32bytes!!"

func newTestAuthService() *auth.Service {
	return auth.NewService(nil, nil, testJWTSecret)
}

func tokenForUser(t *testing.T, svc *auth.Service, userID, email string, roles []string) string {
	t.Helper()
	tok, err := svc.GenerateTestToken(userID, email, roles)
	if err != nil {
		t.Fatalf("failed to generate test token: %v", err)
	}
	return tok
}

// setupEcho creates an Echo instance wired with JWT auth and RBAC middleware,
// then registers the supplied routes. Returns the Echo instance.
func setupEcho(authSvc *auth.Service) *echo.Echo {
	e := echo.New()
	e.Use(middleware.JWTAuth(authSvc, []string{"/health", "/api/v1/files/download/*"}))
	return e
}

// parseResponse is a helper to decode the standard API envelope.
func parseResponse(t *testing.T, rec *httptest.ResponseRecorder) common.APIResponse {
	t.Helper()
	var resp common.APIResponse
	if err := json.Unmarshal(rec.Body.Bytes(), &resp); err != nil {
		t.Fatalf("failed to parse response body: %v (body: %s)", err, rec.Body.String())
	}
	return resp
}

// ---------------------------------------------------------------------------
// A) AUTHZ BOUNDARY TESTS
// ---------------------------------------------------------------------------

// TestAuthzBoundary_Unauthenticated_401 proves that a protected route denies
// unauthenticated requests with 401.
func TestAuthzBoundary_Unauthenticated_401(t *testing.T) {
	authSvc := newTestAuthService()
	e := setupEcho(authSvc)

	// Register a protected admin route.
	adminGroup := e.Group("/api/v1/admin")
	adminGroup.Use(middleware.RequireRole(common.RoleAdministrator))
	adminGroup.GET("/approvals", func(c echo.Context) error {
		return common.Success(c, []string{})
	})

	req := httptest.NewRequest(http.MethodGet, "/api/v1/admin/approvals", nil)
	rec := httptest.NewRecorder()
	e.ServeHTTP(rec, req)

	if rec.Code != http.StatusUnauthorized {
		t.Errorf("expected 401 for unauthenticated request, got %d", rec.Code)
	}

	resp := parseResponse(t, rec)
	if resp.Success {
		t.Error("expected success=false for unauthenticated request")
	}
}

// TestAuthzBoundary_WrongRole_403 proves that a protected admin route denies
// a user with the wrong role with 403.
func TestAuthzBoundary_WrongRole_403(t *testing.T) {
	authSvc := newTestAuthService()
	e := setupEcho(authSvc)

	// Register a protected admin-only route.
	adminGroup := e.Group("/api/v1/admin")
	adminGroup.Use(middleware.RequireRole(common.RoleAdministrator))
	adminGroup.GET("/approvals", func(c echo.Context) error {
		return common.Success(c, []string{})
	})

	// Generate token with traveler role (not admin).
	token := tokenForUser(t, authSvc, "user-traveler", "traveler@test.com", []string{common.RoleTraveler})

	req := httptest.NewRequest(http.MethodGet, "/api/v1/admin/approvals", nil)
	req.Header.Set("Authorization", "Bearer "+token)
	rec := httptest.NewRecorder()
	e.ServeHTTP(rec, req)

	if rec.Code != http.StatusForbidden {
		t.Errorf("expected 403 for wrong role, got %d (body: %s)", rec.Code, rec.Body.String())
	}

	resp := parseResponse(t, rec)
	if resp.Success {
		t.Error("expected success=false for wrong-role request")
	}
}

// TestAuthzBoundary_CorrectRole_200 proves that a user with the correct admin
// role can access the protected route.
func TestAuthzBoundary_CorrectRole_200(t *testing.T) {
	authSvc := newTestAuthService()
	e := setupEcho(authSvc)

	// Register a protected admin-only route.
	adminGroup := e.Group("/api/v1/admin")
	adminGroup.Use(middleware.RequireRole(common.RoleAdministrator))
	adminGroup.GET("/approvals", func(c echo.Context) error {
		return common.Success(c, []string{"approval-1"})
	})

	token := tokenForUser(t, authSvc, "admin-1", "admin@test.com", []string{common.RoleAdministrator})

	req := httptest.NewRequest(http.MethodGet, "/api/v1/admin/approvals", nil)
	req.Header.Set("Authorization", "Bearer "+token)
	rec := httptest.NewRecorder()
	e.ServeHTTP(rec, req)

	if rec.Code != http.StatusOK {
		t.Errorf("expected 200 for admin role, got %d (body: %s)", rec.Code, rec.Body.String())
	}

	resp := parseResponse(t, rec)
	if !resp.Success {
		t.Error("expected success=true for authorized admin request")
	}
}

// TestAuthzBoundary_AccountantFinanceRoute proves that accountant role can
// access finance routes while a traveler cannot.
func TestAuthzBoundary_AccountantFinanceRoute(t *testing.T) {
	authSvc := newTestAuthService()
	e := setupEcho(authSvc)

	// Register a route requiring accountant or admin.
	e.POST("/api/v1/refunds", func(c echo.Context) error {
		return common.Created(c, map[string]string{"message": "refund processed"})
	}, middleware.RequireRole(common.RoleAccountant, common.RoleAdministrator))

	// Traveler should get 403.
	travelerToken := tokenForUser(t, authSvc, "user-t", "t@test.com", []string{common.RoleTraveler})
	req := httptest.NewRequest(http.MethodPost, "/api/v1/refunds", strings.NewReader(`{}`))
	req.Header.Set("Authorization", "Bearer "+travelerToken)
	req.Header.Set("Content-Type", "application/json")
	rec := httptest.NewRecorder()
	e.ServeHTTP(rec, req)

	if rec.Code != http.StatusForbidden {
		t.Errorf("expected 403 for traveler on finance route, got %d", rec.Code)
	}

	// Accountant should get through.
	accountantToken := tokenForUser(t, authSvc, "user-a", "a@test.com", []string{common.RoleAccountant})
	req2 := httptest.NewRequest(http.MethodPost, "/api/v1/refunds", strings.NewReader(`{}`))
	req2.Header.Set("Authorization", "Bearer "+accountantToken)
	req2.Header.Set("Content-Type", "application/json")
	rec2 := httptest.NewRecorder()
	e.ServeHTTP(rec2, req2)

	if rec2.Code != http.StatusCreated {
		t.Errorf("expected 201 for accountant on finance route, got %d", rec2.Code)
	}
}

// ---------------------------------------------------------------------------
// B) RISK-BLOCKED WORKFLOW TEST
// ---------------------------------------------------------------------------

// TestRiskBlockedWithdrawal_DeniesWhenRiskBlocks proves that the withdrawal
// handler returns 403 when the risk service blocks the action.
// We simulate this at the handler level using the actual middleware + service
// error shape that the finance handler uses.
func TestRiskBlockedWithdrawal_DeniesWhenRiskBlocks(t *testing.T) {
	authSvc := newTestAuthService()
	e := setupEcho(authSvc)

	// Simulate the withdrawal endpoint that checks risk.
	// In the real code, finance.Service.RequestWithdrawal calls riskSvc.EvaluateAction.
	// Here we simulate the handler returning the same error shape when risk blocks.
	e.POST("/api/v1/withdrawals", func(c echo.Context) error {
		// Simulate risk-engine block: the service would return a ForbiddenError.
		riskBlocked := true
		if riskBlocked {
			err := common.NewForbiddenError("action blocked by risk engine: account is blacklisted")
			// Map through handler error path (same as finance handler).
			de, ok := err.(*common.DomainError)
			if ok && de.Code == common.ErrCodeForbidden {
				return common.Error(c, http.StatusForbidden, de.Code, de.Message)
			}
			return common.Error(c, http.StatusInternalServerError, "INTERNAL_ERROR", "unexpected")
		}
		return common.Created(c, map[string]string{"id": "w-1"})
	}, middleware.RequireRole(common.RoleCourierRunner))

	// Courier token.
	token := tokenForUser(t, authSvc, "courier-1", "courier@test.com", []string{common.RoleCourierRunner})

	body := `{"amount": 100.00}`
	req := httptest.NewRequest(http.MethodPost, "/api/v1/withdrawals", strings.NewReader(body))
	req.Header.Set("Authorization", "Bearer "+token)
	req.Header.Set("Content-Type", "application/json")
	rec := httptest.NewRecorder()
	e.ServeHTTP(rec, req)

	if rec.Code != http.StatusForbidden {
		t.Errorf("expected 403 for risk-blocked withdrawal, got %d (body: %s)", rec.Code, rec.Body.String())
	}

	resp := parseResponse(t, rec)
	if resp.Success {
		t.Error("expected success=false for risk-blocked withdrawal")
	}
	if resp.Error == nil || !strings.Contains(resp.Error.Message, "risk engine") {
		t.Errorf("expected risk engine mention in error message, got: %+v", resp.Error)
	}
}

// TestRiskBlockedRefund_DeniesWhenRiskBlocks simulates a refund blocked by risk.
func TestRiskBlockedRefund_DeniesWhenRiskBlocks(t *testing.T) {
	authSvc := newTestAuthService()
	e := setupEcho(authSvc)

	e.POST("/api/v1/refunds", func(c echo.Context) error {
		// Simulate risk engine blocking the refund.
		err := common.NewForbiddenError("action blocked by risk engine: too many cancellations in 24 hours")
		de := err.(*common.DomainError)
		return common.Error(c, http.StatusForbidden, de.Code, de.Message)
	}, middleware.RequireRole(common.RoleAccountant, common.RoleAdministrator))

	token := tokenForUser(t, authSvc, "accountant-1", "accountant@test.com", []string{common.RoleAccountant})

	body := `{"amount": 50.00, "orderType": "booking", "orderId": "b-1", "reason": "test"}`
	req := httptest.NewRequest(http.MethodPost, "/api/v1/refunds", strings.NewReader(body))
	req.Header.Set("Authorization", "Bearer "+token)
	req.Header.Set("Content-Type", "application/json")
	rec := httptest.NewRecorder()
	e.ServeHTTP(rec, req)

	if rec.Code != http.StatusForbidden {
		t.Errorf("expected 403 for risk-blocked refund, got %d", rec.Code)
	}

	resp := parseResponse(t, rec)
	if resp.Error == nil || !strings.Contains(resp.Error.Message, "risk engine") {
		t.Errorf("expected risk engine mention, got: %+v", resp.Error)
	}
}

// ---------------------------------------------------------------------------
// C) FILE-TOKEN DOWNLOAD FLOW TESTS
// ---------------------------------------------------------------------------

// TestFileTokenFlow_AuthorizedTokenCreation proves that an authenticated user
// can request a download token on a file endpoint, and the response shape is correct.
func TestFileTokenFlow_AuthorizedTokenCreation(t *testing.T) {
	authSvc := newTestAuthService()
	e := setupEcho(authSvc)

	// Simulate the download-token endpoint.
	e.POST("/api/v1/files/:id/download-token", func(c echo.Context) error {
		userID := common.GetUserID(c)
		if userID == "" {
			return common.Error(c, http.StatusUnauthorized, "UNAUTHORIZED", "authentication required")
		}
		fileID := c.Param("id")
		return common.Created(c, map[string]interface{}{
			"token":     "abc123token",
			"fileId":    fileID,
			"actorId":   userID,
			"expiresAt": "2099-01-01T00:00:00Z",
			"singleUse": true,
		})
	})

	token := tokenForUser(t, authSvc, "user-owner", "owner@test.com", []string{common.RoleTraveler})

	body := `{"ttlSeconds": 300, "singleUse": true}`
	req := httptest.NewRequest(http.MethodPost, "/api/v1/files/file-123/download-token", strings.NewReader(body))
	req.Header.Set("Authorization", "Bearer "+token)
	req.Header.Set("Content-Type", "application/json")
	rec := httptest.NewRecorder()
	e.ServeHTTP(rec, req)

	if rec.Code != http.StatusCreated {
		t.Errorf("expected 201 for authorized token creation, got %d (body: %s)", rec.Code, rec.Body.String())
	}

	resp := parseResponse(t, rec)
	if !resp.Success {
		t.Error("expected success=true for authorized token creation")
	}

	// Verify response shape includes expected fields.
	data, ok := resp.Data.(map[string]interface{})
	if !ok {
		t.Fatal("expected data to be a map")
	}
	if data["token"] == nil || data["fileId"] == nil {
		t.Error("expected token and fileId in response data")
	}
}

// TestFileTokenFlow_UnauthenticatedDenied proves that an unauthenticated user
// cannot create a download token (401).
func TestFileTokenFlow_UnauthenticatedDenied(t *testing.T) {
	authSvc := newTestAuthService()
	e := setupEcho(authSvc)

	e.POST("/api/v1/files/:id/download-token", func(c echo.Context) error {
		userID := common.GetUserID(c)
		if userID == "" {
			return common.Error(c, http.StatusUnauthorized, "UNAUTHORIZED", "authentication required")
		}
		return common.Created(c, map[string]string{"token": "should-not-reach"})
	})

	// No auth header.
	req := httptest.NewRequest(http.MethodPost, "/api/v1/files/file-123/download-token", strings.NewReader(`{}`))
	req.Header.Set("Content-Type", "application/json")
	rec := httptest.NewRecorder()
	e.ServeHTTP(rec, req)

	if rec.Code != http.StatusUnauthorized {
		t.Errorf("expected 401 for unauthenticated token request, got %d", rec.Code)
	}
}

// TestFileTokenFlow_UnauthorizedActorDenied proves that a user who doesn't own
// the file and isn't admin gets 403 when creating a download token.
func TestFileTokenFlow_UnauthorizedActorDenied(t *testing.T) {
	authSvc := newTestAuthService()
	e := setupEcho(authSvc)

	// Simulate the endpoint where the service checks ownership.
	e.POST("/api/v1/files/:id/download-token", func(c echo.Context) error {
		userID := common.GetUserID(c)
		if userID == "" {
