1	import { useState, useCallback } from "react";
2	import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
3	import api from "@/lib/api";
4	
5	interface FileRecord {
6	  id: string;
7	  name: string;
8	  type: string;
9	  size: number;
10	  encrypted: boolean;
11	  createdAt: string;
12	  downloadUrl?: string;
13	}
14	
15	interface ContractTemplate {
16	  id: string;
17	  name: string;
18	  description: string;
19	  version: string;
20	}
21	
22	interface InvoiceRequest {
23	  id: string;
24	  bookingId: string;
25	  status: string;
26	  amount: number;
27	  createdAt: string;
28	}
29	
30	const STATUS_COLORS: Record<string, string> = {
31	  pending: "bg-yellow-100 text-yellow-800",
32	  generated: "bg-green-100 text-green-700",
33	  sent: "bg-blue-100 text-blue-700",
34	  paid: "bg-green-100 text-green-700",
35	  cancelled: "bg-red-100 text-red-700",
36	};
37	
38	function formatBytes(bytes: number): string {
39	  if (bytes === 0) return "0 B";
40	  const k = 1024;
41	  const sizes = ["B", "KB", "MB", "GB"];
42	  const i = Math.floor(Math.log(bytes) / Math.log(k));
43	  return `${parseFloat((bytes / Math.pow(k, i)).toFixed(1))} ${sizes[i]}`;
44	}
45	
46	function formatDate(iso: string): string {
47	  return new Date(iso).toLocaleDateString("en-US", {
48	    month: "short",
49	    day: "numeric",
50	    year: "numeric",
51	  });
52	}
53	
54	function formatMoney(cents: number): string {
55	  return `$${(cents / 100).toLocaleString("en-US", { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
56	}
57	
58	function statusLabel(status: string): string {
59	  return status.replace(/_/g, " ").replace(/\b\w/g, (c) => c.toUpperCase());
60	}
61	
62	export default function DocumentCenter() {
63	  const [dragOver, setDragOver] = useState(false);
64	  const [showInvoiceModal, setShowInvoiceModal] = useState(false);
65	  const [invoiceBookingId, setInvoiceBookingId] = useState("");
66	  const [invoiceAmount, setInvoiceAmount] = useState("");
67	  const qc = useQueryClient();
68	
69	  // NOTE: No GET /files list endpoint exists. Using /files/record/:recordType/:recordId
70	  // for contextual file lookups. For now, this query is disabled until a record context is provided.
71	  const [recordType] = useState("booking");
72	  const [recordId] = useState("");
73	  const { data: files, isLoading: filesLoading } = useQuery<FileRecord[]>({
74	    queryKey: ["files", recordType, recordId],
75	    queryFn: async () => {
76	      const { data } = await api.get(`/files/record/${recordType}/${recordId}`);
77	      return data.data ?? data;
78	    },
79	    enabled: !!recordId,
80	  });
81	
82	  const { data: templates } = useQuery<ContractTemplate[]>({
83	    queryKey: ["contract-templates"],
84	    queryFn: async () => {
85	      const { data } = await api.get("/contract-templates");
86	      return data.data ?? data;
87	    },
88	  });
89	
90	  const { data: invoices } = useQuery<InvoiceRequest[]>({
91	    queryKey: ["invoice-requests"],
92	    queryFn: async () => {
93	      const { data } = await api.get("/invoice-requests");
94	      return data.data ?? data;
95	    },
96	  });
97	
98	  const uploadMutation = useMutation({
99	    mutationFn: async (file: File) => {
100	      const formData = new FormData();
101	      formData.append("file", file);
102	      const { data } = await api.post("/files/upload", formData, {
103	        headers: { "Content-Type": "multipart/form-data" },
104	      });
105	      return data;
106	    },
107	    onSuccess: () => {
108	      qc.invalidateQueries({ queryKey: ["files"] });
109	    },
110	  });
111	
112	  const generateContractMutation = useMutation({
113	    mutationFn: async (templateId: string) => {
114	      const { data } = await api.post(`/contracts/generate`, { templateId });
115	      return data;
116	    },
117	    onSuccess: () => {
118	      qc.invalidateQueries({ queryKey: ["files"] });
119	    },
120	  });
121	
122	  const requestInvoiceMutation = useMutation({
123	    mutationFn: async (payload: { bookingId: string; amount: number }) => {
124	      const { data } = await api.post("/invoice-requests", payload);
125	      return data;
126	    },
127	    onSuccess: () => {
128	      setShowInvoiceModal(false);
129	      setInvoiceBookingId("");
130	      setInvoiceAmount("");
131	      qc.invalidateQueries({ queryKey: ["invoice-requests"] });
132	    },
133	  });
134	
135	  const handleDownload = async (fileId: string, fileName: string) => {
136	    try {
137	      const { data: tokenData } = await api.post(`/files/${fileId}/download-token`);
138	      const token = tokenData.data?.token ?? tokenData.token;
139	      const response = await api.get(`/files/download/${token}`, {
140	        responseType: "blob",
141	      });
142	      const url = window.URL.createObjectURL(new Blob([response.data]));
143	      const link = document.createElement("a");
144	      link.href = url;
145	      link.download = fileName;
146	      document.body.appendChild(link);
147	      link.click();
148	      link.remove();
149	      window.URL.revokeObjectURL(url);
150	    } catch {
151	      // Download error handled silently
152	    }
153	  };
154	
155	  const handleFileInput = (e: React.ChangeEvent<HTMLInputElement>) => {
156	    const fileList = e.target.files;
157	    if (fileList) {
158	      Array.from(fileList).forEach((file) => uploadMutation.mutate(file));
159	    }
160	  };
161	
162	  const handleDrop = useCallback(
163	    (e: React.DragEvent) => {
164	      e.preventDefault();
165	      setDragOver(false);
166	      const droppedFiles = e.dataTransfer.files;
167	      Array.from(droppedFiles).forEach((file) => uploadMutation.mutate(file));
168	    },
169	    [uploadMutation],
170	  );
171	
172	  const handleDragOver = useCallback((e: React.DragEvent) => {
173	    e.preventDefault();
174	    setDragOver(true);
175	  }, []);
176	
177	  const handleDragLeave = useCallback(() => {
178	    setDragOver(false);
179	  }, []);
180	
181	  return (
182	    <div className="space-y-6">
183	      <div>
184	        <h1 className="text-2xl font-bold text-gray-900">Documents</h1>
185	        <p className="mt-1 text-gray-500">Manage and share documents.</p>
186	      </div>
187	
188	      {/* Upload Area */}
189	      <div
190	        onDrop={handleDrop}
191	        onDragOver={handleDragOver}
192	        onDragLeave={handleDragLeave}
193	        className={`flex flex-col items-center justify-center rounded-xl border-2 border-dashed p-8 transition-colors ${
194	          dragOver
195	            ? "border-indigo-400 bg-indigo-50"
196	            : "border-gray-300 bg-white hover:border-gray-400"
197	        }`}
198	      >
199	        <p className="text-sm text-gray-600">
200	          Drag and drop files here, or{" "}
201	          <label className="cursor-pointer font-medium text-indigo-600 hover:text-indigo-700">
202	            browse
203	            <input
204	              type="file"
205	              multiple
206	              onChange={handleFileInput}
207	              className="hidden"
208	            />
209	          </label>
210	        </p>
211	        {uploadMutation.isPending && (
212	          <p className="mt-2 text-sm text-indigo-600">Uploading...</p>
213	        )}
214	        {uploadMutation.isError && (
215	          <p className="mt-2 text-sm text-red-600">Upload failed. Please try again.</p>
216	        )}
217	        {uploadMutation.isSuccess && (
218	          <p className="mt-2 text-sm text-green-600">File uploaded successfully.</p>
219	        )}
220	      </div>
221	
222	      {/* Files List */}
223	      <div className="rounded-xl border border-gray-200 bg-white">
224	        <div className="border-b border-gray-200 px-6 py-4">
225	          <h2 className="text-lg font-semibold text-gray-900">Files</h2>
226	        </div>
227	        {filesLoading ? (
228	          <div className="p-6 text-center text-gray-500">Loading files...</div>
229	        ) : !files?.length ? (
230	          <div className="p-6 text-center text-gray-500">
231	            No files uploaded yet.
232	          </div>
233	        ) : (
234	          <table className="w-full text-left text-sm">
235	            <thead className="border-b border-gray-200 bg-gray-50">
236	              <tr>
237	                <th className="px-6 py-3 font-medium text-gray-600">Name</th>
238	                <th className="px-6 py-3 font-medium text-gray-600">Type</th>
239	                <th className="px-6 py-3 font-medium text-gray-600">Size</th>
240	                <th className="px-6 py-3 font-medium text-gray-600">Security</th>
241	                <th className="px-6 py-3 font-medium text-gray-600">Uploaded</th>
242	                <th className="px-6 py-3 font-medium text-gray-600">Actions</th>
243	              </tr>
244	            </thead>
245	            <tbody className="divide-y divide-gray-100">
246	              {files.map((file) => (
247	                <tr key={file.id} className="hover:bg-gray-50">
248	                  <td className="px-6 py-3 font-medium text-gray-900">
249	                    {file.name}
250	                  </td>
251	                  <td className="px-6 py-3 text-gray-600">{file.type}</td>
252	                  <td className="px-6 py-3 text-gray-600">
253	                    {formatBytes(file.size)}
254	                  </td>
255	                  <td className="px-6 py-3">
256	                    {file.encrypted ? (
257	                      <span className="rounded-full bg-green-100 px-2.5 py-0.5 text-xs font-medium text-green-700">
258	                        Encrypted
259	                      </span>
260	                    ) : (
261	                      <span className="text-xs text-gray-400">Standard</span>
262	                    )}
263	                  </td>
264	                  <td className="px-6 py-3 text-gray-500">
265	                    {formatDate(file.createdAt)}
266	                  </td>
267	                  <td className="px-6 py-3">
268	                    <button
269	                      onClick={() => handleDownload(file.id, file.name)}
270	                      className="text-sm font-medium text-indigo-600 hover:text-indigo-700"
271	                    >
272	                      Download
273	                    </button>
274	                  </td>
275	                </tr>
276	              ))}
277	            </tbody>
278	          </table>
279	        )}
280	      </div>
281	
